package com.eas.ui.admin;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class LeaveApprovalPanel extends ReadOnlyQueryPanel { private final UserSession session; private final JTextField remarks=new JTextField(30); public LeaveApprovalPanel(UserSession s){super("Leave Request Processing","SELECT * FROM v_leave_monitoring ORDER BY id DESC","SELECT * FROM v_leave_monitoring WHERE employee_no LIKE ? OR full_name LIKE ? OR status LIKE ? ORDER BY id DESC","leave_requests");session=s;JPanel p=new JPanel();p.add(new JLabel("Admin Remarks"));p.add(remarks);JButton approve=UITheme.button("APPROVE");JButton reject=UITheme.button("REJECT");p.add(approve);p.add(reject);add(p,BorderLayout.SOUTH);approve.addActionListener(e->review("APPROVED"));reject.addActionListener(e->review("REJECTED"));}
 private void review(String status){int r=table.getSelectedRow();if(r<0){Dialogs.error(this,"Select a leave request.");return;}int id=Integer.parseInt(table.getValueAt(r,0).toString());try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement("UPDATE leave_requests SET status=?,reviewed_by=?,reviewed_at=NOW(),admin_remarks=? WHERE id=? AND status='PENDING'")){p.setString(1,status);p.setInt(2,session.getId());p.setString(3,remarks.getText().trim());p.setInt(4,id);if(p.executeUpdate()==0)throw new SQLException("Only pending leave requests can be reviewed.");AuditService.log(session.getId(),status,"LEAVE","Reviewed leave request #"+id);load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
